INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('social-worker-moex-07410', 'social-worker', 'social-worker-moex-100-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '下列詠史之作，與「楚 漢相爭」人物無關的是：', '["八尺將軍千里騅，拔山扛鼎不妨奇。范增力盡無施處，路到烏江君自知", "不握兵權只坐籌，苦辭萬戶乞討留。縱令不早尋仙去，天子終無賜醢謀", "久與君王共苦辛，功成身退步逡巡。五湖渺渺煙波闊，誰是扁舟第二人", "鳥盡良弓勢必藏，千秋青史費評章。區區一飯猶圖報，爭肯為臣負漢王"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:38+00:00", "source_pdf_sha1": "d3581385397e", "answer_pdf_sha1": "a0a9d5185232", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "902", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07411', 'social-worker', 'social-worker-moex-100-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '凡要說的有三個以上的事物，這些事物又有大小輕重等比例，於是說話行文時，依序層層遞推，這種修 辭方法叫做「層遞」。下列文句屬於「層遞」的是：', '["將軍百戰死，壯士十年歸，歸來見天子，天子坐明堂", "知者不惑，仁者不憂，勇者不懼", "先父族，次母族，次妻族，而後及其疏遠之賢", "夫天地者，萬物之逆旅也；光陰者，百代之過客也 ⑤五霸莫盛於桓、文，文公之才，不過桓公，其臣又皆不及仲"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:38+00:00", "source_pdf_sha1": "d3581385397e", "answer_pdf_sha1": "a0a9d5185232", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "902", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07412', 'social-worker', 'social-worker-moex-100-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '下列語文常識中，說明正確的是：', '["六書中以「形聲字」最多，如「江」、「射」、「問」皆屬形聲字", "「金文」是流行於商、周時期，鑄刻於青銅器上的文字，也稱鐘鼎文字", "「馬拉松」、「宅急便」、「水噹噹」、「瑜珈」都是時下流行的外來語", "「零落」、「參差」、「躊躇」、「落寞」都是雙聲的聯綿詞"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:38+00:00", "source_pdf_sha1": "d3581385397e", "answer_pdf_sha1": "a0a9d5185232", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "902", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07413', 'social-worker', 'social-worker-moex-100-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '下列四首詩，各詠贊一位佳人，請依四位佳人所處時代之先後，排出正確順序：', '["飄飄秀色奪仙春，只恐丹青畫不真。能為君主罷征戍，甘心玉骨葬胡塵", "華清恩幸古無倫，猶恐蛾眉不勝人。未免被他褒女笑，只叫天子暫蒙塵", "長揖雄談態自殊，美人巨眼識窮途，屍居餘氣楊公幕，豈得羈縻女丈夫", "遺恨江東應未消，芳魂零亂任西飄，八千子弟同歸漢，不負君恩是楚腰"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:38+00:00", "source_pdf_sha1": "d3581385397e", "answer_pdf_sha1": "a0a9d5185232", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "902", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07414', 'social-worker', 'social-worker-moex-100-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '張潮《幽夢影》：「梅邊之石宜古，松下之石宜拙，竹旁之石宜   ，盆內之石宜   」，上引文句中應 填入的字，最恰當的選項是：', '["巧／瘦", "小／峭", "瘦／巧", "小／巧"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:38+00:00", "source_pdf_sha1": "d3581385397e", "answer_pdf_sha1": "a0a9d5185232", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "902", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07415', 'social-worker', 'social-worker-moex-100-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '①三吏三別之後／兩鬢已蒼／也該寫點雲淡風輕的自己了／躑躇浣花溪頭／忽然水一般靜了下來', '["風靜了，我是／默默的雪。他在／敗葦間穿行，好落寞的／神色，這人一朝是／東京八十萬禁軍教頭／ 如今行船悄悄向梁山落草／山是憂戚的樣子", "我打此經過／寫了幾首詩／和女子調笑／他們戲稱我為／帝王／歷史要數說我／亡國的罪愆／但是／ 我的罪／何止亡國", "詩史寫到建安就得爬一座大山／歌雖然短／但沒酒不行／朝露被逐呎的海拔逐呎驅散／聽覺裡全是呦 呦的鹿鳴 以上新詩所指涉的對象依序是：", "杜甫／宋江／劉義慶／劉伶"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:38+00:00", "source_pdf_sha1": "d3581385397e", "answer_pdf_sha1": "a0a9d5185232", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "902", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07416', 'social-worker', 'social-worker-moex-100-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '文中晏子不死君難，主要是因為他認為：', '["大臣身負國家重任，不可輕易言死", "莊公不應私通棠姜，贊成崔子弒君", "保留有用之身，才可以伺機為國君報仇", "國君不是因社稷而亡，大臣沒有必要殉死"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:38+00:00", "source_pdf_sha1": "d3581385397e", "answer_pdf_sha1": "a0a9d5185232", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "902", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07417', 'social-worker', 'social-worker-moex-100-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '文中「臣君者，豈為其口實」，意謂為人臣子：', '["不是為了拿俸祿來供養自己", "不可落人口實，受人非議", "怎麼可以做出弒君這種天理不容的事情呢", "可以找藉口推卸責任嗎"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:38+00:00", "source_pdf_sha1": "d3581385397e", "answer_pdf_sha1": "a0a9d5185232", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "902", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07418', 'social-worker', 'social-worker-moex-100-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '下列敘述何者錯誤？', '["本文屬記敘文，記述齊卿崔武子弒君，而晏子不死君難之事", "「君為社稷死則死之」意謂：國君為國家而死就應該讓他死得安心", "晏子「枕尸股而哭，興，三踊而出」是表示哀痛，以盡臣子之禮", "崔武子不殺晏子，是因為晏子深得民望，放了他可以收攬民心 吳王欲從民飲酒，伍子胥諫曰：「不可。昔白龍下清冷之淵，化為魚，漁者豫且射中其目，白龍上 訴天帝，天帝曰：『當是之時，若安置而形？』白龍對曰：『我下清冷之淵，化為魚。』天帝曰：『魚 固人之所射也，若是，豫且何罪？』夫白龍，天帝貴畜也。豫且，宋國賤臣也。白龍不化，豫且不射。 今棄萬乘之位，而從布衣之士飲酒，臣恐其有豫且之患矣！」王乃止。（劉向《說苑．正諫》） 請依上文回答17至18題"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:38+00:00", "source_pdf_sha1": "d3581385397e", "answer_pdf_sha1": "a0a9d5185232", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "902", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07419', 'social-worker', 'social-worker-moex-100-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '文中吳王被比喻作：', '["天帝", "白龍", "豫且", "賤臣"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:38+00:00", "source_pdf_sha1": "d3581385397e", "answer_pdf_sha1": "a0a9d5185232", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "902", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
